import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import { useInView } from 'react-intersection-observer';
import { BrowserRouter as Router, Route, Routes, useNavigate, useLocation } from 'react-router-dom';

function shuffleArray(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

const Video = ({ src, videoID, onVideoClick }) => {
  const { ref, inView } = useInView({
    triggerOnce: true,
    threshold: 0.1,
  });

  return (
    <video
      ref={ref}
      src={src}
      autoPlay
      loop
      muted
      playsInline
      loading="lazy"
      className={inView ? 'fade-in' : ''}
      onClick={() => onVideoClick(videoID)}
    />
  );
};

const Modal = ({ videoInfo, onClose }) => {
  // Function to detect the URL is from Vimeo and return the appropriate embed URL
  const getEmbeddedVideoUrl = (url) => {
    // Assuming the URL format is like "https://vimeo.com/343497333/31d0a6e614?share=copy"
    // and need to extract the numeric ID immediately after "vimeo.com/"
    const vimeoId = url.split("vimeo.com/")[1].split('/')[0]; // Extracts the ID before any additional path segments or query strings
    return `https://player.vimeo.com/video/${vimeoId}`;
  };

  return (
    <div className="modal">
      <div className="modal-content">
        <span className="close" onClick={onClose}>&times;</span>
        <h2>{videoInfo.videoName}</h2> {/* Display video name as header */}
        <iframe
          src={getEmbeddedVideoUrl(videoInfo.URL)} // Embed video using the correct URL
          frameBorder="0"
          allow="autoplay; fullscreen"
          allowFullScreen
          title={videoInfo.videoName}
          width="560"
          height="315"
        ></iframe>
        <p style={{ whiteSpace: 'pre-wrap' }}>{videoInfo.Description || ''}</p> {/* Display description, respecting line breaks */}
      </div>
    </div>
  );
};

function App() {
  const [scenes, setScenes] = useState([]);
  const [selectedVideoInfo, setSelectedVideoInfo] = useState(null);
  const navigate = useNavigate();
  const location = useLocation();

  // Effect for initial data fetch and shuffle
  useEffect(() => {
    axios.get('https://fierce-springs-10022-1e7f8f8c4e94.herokuapp.com/videos')
      .then(response => {
        // Ensure shuffle only occurs once on initial load
        if(scenes.length === 0) { // Check if scenes is empty to avoid reshuffling
          setScenes(shuffleArray(response.data));
        }
      })
      .catch(error => {
        console.error('Error fetching data: ', error);
      });
  }, []); // Empty dependency array to ensure this runs only once on mount

  // Separate effect for handling video selection from URL
  useEffect(() => {
    const videoID = location.pathname.split('/videos/')[1];
    if (videoID) {
      handleVideoClick(videoID);
    }
  }, [location.pathname]); // Dependency on location.pathname to re-run only when URL changes

  function handleVideoClick(videoID) {
    axios.get(`https://fierce-springs-10022-1e7f8f8c4e94.herokuapp.com/video_info/${videoID}`)
      .then(response => {
        setSelectedVideoInfo(response.data);
        navigate(`/videos/${videoID}`);
      })
      .catch(error => {
        console.error('Error fetching video info: ', error);
      });
  }

  function handleCloseModal() {
    setSelectedVideoInfo(null);
    navigate('/');
  }

  return (
    <div className="App">
      <div className="video-grid">
        {scenes.map(scene => (
          <Video
            key={scene.sceneURL}
            src={scene.sceneURL}
            videoID={scene.videoID}
            onVideoClick={handleVideoClick}
          />
        ))}
      </div>
      {selectedVideoInfo && <Modal videoInfo={selectedVideoInfo} onClose={handleCloseModal} />}
    </div>
  );
}

function AppWrapper() {
  return (
    <Router>
      <Routes>
        <Route path="/videos/:videoID" element={<App />} />
        <Route path="/" element={<App />} />
      </Routes>
    </Router>
  );
}

export default AppWrapper;
